use criterion::{black_box, criterion_group, criterion_main, Criterion};
use json_schema_graphql_converter::{ConversionOptions, Converter};

const JSON_SCHEMA: &str = r#"{
    "$schema": "https://json-schema.org/draft/2020-12/schema",
    "type": "object",
    "x-graphql-type-name": "User",
    "properties": {
        "id": {
            "type": "string",
            "x-graphql-type": "ID!"
        },
        "name": {
            "type": "string"
        },
        "email": {
            "type": "string"
        },
        "age": {
            "type": "integer"
        },
        "tags": {
            "type": "array",
            "items": {
                "type": "string"
            }
        },
        "address": {
            "type": "object",
            "properties": {
                "street": { "type": "string" },
                "city": { "type": "string" },
                "zip": { "type": "string" }
            }
        }
    }
}"#;

const GRAPHQL_SDL: &str = r#"
type Address {
    street: String
    city: String
    zip: String
}

type User {
    id: ID!
    name: String
    email: String
    age: Int
    tags: [String]
    address: Address
}

type Query {
    user(id: ID!): User
    users: [User]
}
"#;

fn bench_json_to_graphql(c: &mut Criterion) {
    let converter = Converter::new();

    c.bench_function("json_schema_to_graphql_small", |b| {
        b.iter(|| {
            converter
                .json_schema_to_graphql(black_box(JSON_SCHEMA))
                .unwrap()
        })
    });
}

fn bench_graphql_to_json(c: &mut Criterion) {
    let converter = Converter::new();

    c.bench_function("graphql_to_json_schema_small", |b| {
        b.iter(|| {
            converter
                .graphql_to_json_schema(black_box(GRAPHQL_SDL))
                .unwrap()
        })
    });
}

fn bench_cached_conversion(c: &mut Criterion) {
    // Only works if caching feature is enabled, but we can benchmark the logic anyway
    // (If feature is disabled, it just won't cache, effectively benchmarking the uncached path again but calling .convert)
    let converter = Converter::new();

    c.bench_function("cached_json_to_graphql", |b| {
        b.iter(|| {
            converter
                .convert(
                    black_box(JSON_SCHEMA),
                    json_schema_graphql_converter::ConversionDirection::JsonSchemaToGraphQL,
                )
                .unwrap()
        })
    });
}

fn bench_with_validation_disabled(c: &mut Criterion) {
    let options = ConversionOptions {
        validate: false,
        ..Default::default()
    };
    let converter = Converter::with_options(options);

    c.bench_function("json_to_graphql_no_validation", |b| {
        b.iter(|| {
            converter
                .json_schema_to_graphql(black_box(JSON_SCHEMA))
                .unwrap()
        })
    });
}

criterion_group!(
    benches,
    bench_json_to_graphql,
    bench_graphql_to_json,
    bench_cached_conversion,
    bench_with_validation_disabled
);
criterion_main!(benches);

use anyhow::{Context, Result};
use clap::Parser;
use json_schema_graphql_converter::{ConversionOptions, Converter};
use std::fs;
use std::path::PathBuf;

/// JSON Schema to GraphQL SDL Converter CLI
#[derive(Parser, Debug)]
#[command(author, version, about, long_about = None)]
struct Args {
    /// Path to local JSON schema file or URL to remote schema
    #[arg(short, long, value_name = "INPUT")]
    input: String,

    /// Output file path (defaults to stdout)
    #[arg(short, long)]
    output: Option<PathBuf>,

    /// Infer ID scalar from fields named "id" or "_id"
    #[arg(long, default_value_t = false)]
    infer_ids: bool,

    /// Disable schema validation
    #[arg(long, default_value_t = false)]
    no_validate: bool,

    /// Include descriptions in output
    #[arg(long, default_value_t = true)]
    descriptions: bool,

    /// Preserve field order
    #[arg(long, default_value_t = true)]
    preserve_order: bool,
}

#[tokio::main]
async fn main() -> Result<()> {
    let args = Args::parse();

    // Fetch input content
    let json_content = if args.input.starts_with("http://") || args.input.starts_with("https://") {
        eprintln!("Fetching schema from {}...", args.input);
        reqwest::get(&args.input)
            .await
            .context("Failed to fetch remote schema")?
            .text()
            .await
            .context("Failed to read response text")?
    } else {
        fs::read_to_string(&args.input)
            .context(format!("Failed to read local file: {}", args.input))?
    };

    // Configure converter
    let options = ConversionOptions {
        validate: !args.no_validate,
        include_descriptions: args.descriptions,
        preserve_field_order: args.preserve_order,
        federation_version: 2,
        infer_ids: args.infer_ids,
    };

    let converter = Converter::with_options(options);

    // Convert
    let graphql_sdl = converter
        .json_schema_to_graphql(&json_content)
        .context("Conversion failed")?;

    // Output
    if let Some(output_path) = args.output {
        fs::write(&output_path, &graphql_sdl)
            .context(format!("Failed to write output to {:?}", output_path))?;
        eprintln!("Successfully converted and saved to {:?}", output_path);
    } else {
        println!("{}", graphql_sdl);
    }

    Ok(())
}

//! Error types for JSON Schema x GraphQL conversion

use serde::Serialize;
use thiserror::Error;

/// Result type for conversion operations
pub type Result<T> = std::result::Result<T, ConversionError>;

/// Errors that can occur during conversion
#[derive(Error, Debug, Serialize)]
#[serde(tag = "type", content = "details")]
pub enum ConversionError {
    /// Invalid JSON Schema input
    #[error("Invalid JSON Schema: {0}")]
    InvalidJsonSchema(String),

    /// Invalid GraphQL SDL input
    #[error("Invalid GraphQL SDL: {0}")]
    InvalidGraphQLSdl(String),

    /// Missing required field or extension
    #[error("Missing required field: {0}")]
    MissingRequiredField(String),

    /// Invalid type definition
    #[error("Invalid type definition: {0}")]
    InvalidType(String),

    /// Invalid field definition
    #[error("Invalid field definition: {0}")]
    InvalidField(String),

    /// Invalid directive
    #[error("Invalid directive: {0}")]
    InvalidDirective(String),

    /// Invalid GraphQL name (must match /^[_A-Za-z][_0-9A-Za-z]*$/)
    #[error("Invalid GraphQL name '{0}': {1}")]
    InvalidGraphQLName(String, String),

    /// Invalid x-graphql extension
    #[error("Invalid x-graphql-* extension: {0}")]
    InvalidExtension(String),

    /// Validation error
    #[error("Validation error: {0}")]
    ValidationError(String),

    /// Federation error
    #[error("Federation error: {0}")]
    FederationError(String),

    /// Unsupported feature
    #[error("Unsupported feature: {0}")]
    UnsupportedFeature(String),

    /// Type mismatch between JSON Schema and GraphQL
    #[error("Type mismatch: {0}")]
    TypeMismatch(String),

    /// Circular reference detected
    #[error("Circular reference detected: {0}")]
    CircularReference(String),

    /// JSON serialization/deserialization error
    #[error("JSON error: {0}")]
    JsonError(String),

    /// Regex error
    #[error("Regex error: {0}")]
    RegexError(String),

    /// Internal conversion error
    #[error("Internal error: {0}")]
    InternalError(String),

    /// Multiple errors occurred
    #[error("Multiple errors: {0:?}")]
    MultipleErrors(Vec<ConversionError>),
}

impl ConversionError {
    /// Create a validation error
    pub fn validation(msg: impl Into<String>) -> Self {
        Self::ValidationError(msg.into())
    }

    /// Create an invalid GraphQL name error
    pub fn invalid_name(name: impl Into<String>, reason: impl Into<String>) -> Self {
        Self::InvalidGraphQLName(name.into(), reason.into())
    }

    /// Create a missing field error
    pub fn missing_field(field: impl Into<String>) -> Self {
        Self::MissingRequiredField(field.into())
    }

    /// Create an invalid extension error
    pub fn invalid_extension(msg: impl Into<String>) -> Self {
        Self::InvalidExtension(msg.into())
    }

    /// Create a type mismatch error
    pub fn type_mismatch(msg: impl Into<String>) -> Self {
        Self::TypeMismatch(msg.into())
    }

    /// Create an unsupported feature error
    pub fn unsupported(msg: impl Into<String>) -> Self {
        Self::UnsupportedFeature(msg.into())
    }

    /// Combine multiple errors into one
    pub fn combine(errors: Vec<ConversionError>) -> Self {
        if errors.len() == 1 {
            errors.into_iter().next().unwrap()
        } else {
            Self::MultipleErrors(errors)
        }
    }
}

impl From<serde_json::Error> for ConversionError {
    fn from(err: serde_json::Error) -> Self {
        ConversionError::JsonError(err.to_string())
    }
}

impl From<regex::Error> for ConversionError {
    fn from(err: regex::Error) -> Self {
        ConversionError::RegexError(err.to_string())
    }
}

#[cfg(feature = "wasm")]
impl From<ConversionError> for wasm_bindgen::JsValue {
    fn from(err: ConversionError) -> Self {
        serde_wasm_bindgen::to_value(&err)
            .unwrap_or_else(|_| wasm_bindgen::JsValue::from_str(&err.to_string()))
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_error_creation() {
        let err = ConversionError::validation("test error");
        assert!(matches!(err, ConversionError::ValidationError(_)));
        assert_eq!(err.to_string(), "Validation error: test error");
    }

    #[test]
    fn test_invalid_name_error() {
        let err = ConversionError::invalid_name("123invalid", "must start with letter");
        assert!(matches!(err, ConversionError::InvalidGraphQLName(_, _)));
        assert!(err.to_string().contains("123invalid"));
        assert!(err.to_string().contains("must start with letter"));
    }

    #[test]
    fn test_combine_errors() {
        let errors = vec![
            ConversionError::validation("error 1"),
            ConversionError::validation("error 2"),
        ];
        let combined = ConversionError::combine(errors);
        assert!(matches!(combined, ConversionError::MultipleErrors(_)));
    }

    #[test]
    fn test_combine_single_error() {
        let errors = vec![ConversionError::validation("single error")];
        let combined = ConversionError::combine(errors);
        assert!(matches!(combined, ConversionError::ValidationError(_)));
    }
}

//! Converts GraphQL SDL to JSON Schema.
//!
//! This module uses `async-graphql` to parse the GraphQL SDL into an Abstract Syntax Tree (AST),
//! then traverses the AST to construct a corresponding JSON Schema.

use crate::error::ConversionError;
use crate::types::{ConversionOptions, GqlScalar, GqlType};
use async_graphql::parser::{
    parse_schema,
    types::{
        BaseType, ConstDirective, FieldDefinition, InputValueDefinition, Type, TypeDefinition,
        TypeKind as AsyncTypeKind, TypeSystemDefinition,
    },
    Positioned,
};
use indexmap::IndexMap;
use serde_json::{json, Value as JsonValue};

// --- Main Conversion Function ---

pub fn convert(sdl: &str, _options: &ConversionOptions) -> Result<String, ConversionError> {
    let doc = parse_schema(sdl).map_err(|e| ConversionError::InvalidGraphQLSdl(e.to_string()))?;
    let dummy_registry = IndexMap::new();
    let context = ConversionContext::new(sdl, &dummy_registry);

    let type_registry: IndexMap<String, TypeDef> = doc
        .definitions
        .into_iter()
        .filter_map(|def| {
            if let TypeSystemDefinition::Type(type_def) = def {
                convert_definition(type_def, &context)
            } else {
                None
            }
        })
        .collect();

    let context = ConversionContext::new(sdl, &type_registry);

    let mut schema_defs = IndexMap::new();
    for (name, type_def) in context.type_registry {
        let schema = convert_type_to_schema(type_def, &context);
        schema_defs.insert(name.clone(), schema);
    }

    let root_ref_name = if type_registry.contains_key("Query") {
        "Query"
    } else {
        type_registry
            .values()
            .find(|def| def.kind == TypeKind::Object)
            .map(|def| def.name.as_str())
            .unwrap_or_else(|| type_registry.keys().next().map_or("", |s| s.as_str()))
    };

    let full_schema = json!({
        "$schema": "http://json-schema.org/draft-07/schema#",
        "$ref": format!("#/definitions/{}", root_ref_name),
        "definitions": schema_defs,
    });

    serde_json::to_string_pretty(&full_schema).map_err(Into::into)
}

// --- Intermediate Representation ---

struct ConversionContext<'a> {
    #[allow(dead_code)]
    sdl: &'a str,
    type_registry: &'a IndexMap<String, TypeDef>,
}

impl<'a> ConversionContext<'a> {
    fn new(sdl: &'a str, type_registry: &'a IndexMap<String, TypeDef>) -> Self {
        Self { sdl, type_registry }
    }
}

#[derive(Debug, Clone)]
struct TypeDef {
    kind: TypeKind,
    name: String,
    description: Option<String>,
    fields: Vec<FieldDef>,
    enum_values: Vec<String>,
    union_types: Vec<String>,
    interfaces: Vec<String>,
    directives: Vec<DirectiveDef>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum TypeKind {
    Object,
    Interface,
    Enum,
    Union,
    InputObject,
    Scalar,
}

#[derive(Debug, Clone)]
struct FieldDef {
    name: String,
    field_type: GqlType,
    description: Option<String>,
    arguments: Vec<ArgumentDef>,
    directives: Vec<DirectiveDef>,
}

#[derive(Debug, Clone)]
struct ArgumentDef {
    name: String,
    arg_type: GqlType,
    description: Option<String>,
    default_value: Option<String>,
}

#[derive(Debug, Clone)]
struct DirectiveDef {
    name: String,
    arguments: IndexMap<String, String>,
}

// --- CST to Intermediate Representation Conversion ---

fn get_description(desc: &Option<Positioned<String>>) -> Option<String> {
    desc.as_ref().map(|d| d.node.clone())
}

fn convert_definition<'a>(
    definition: Positioned<TypeDefinition>,
    context: &'a ConversionContext,
) -> Option<(String, TypeDef)> {
    let name = definition.node.name.node.to_string();
    let description = get_description(&definition.node.description);
    let directives = definition
        .node
        .directives
        .iter()
        .map(|d| convert_directive(d))
        .collect::<Vec<_>>();

    let type_def = match &definition.node.kind {
        AsyncTypeKind::Object(def) => Some((
            name.clone(),
            TypeDef {
                kind: TypeKind::Object,
                name: name.clone(),
                description: description.clone(),
                fields: def
                    .fields
                    .iter()
                    .map(|f| convert_field(f, context))
                    .collect(),
                enum_values: vec![],
                union_types: vec![],
                interfaces: def.implements.iter().map(|i| i.node.to_string()).collect(),
                directives,
            },
        )),
        AsyncTypeKind::Interface(def) => Some((
            name.clone(),
            TypeDef {
                kind: TypeKind::Interface,
                name: name.clone(),
                description: description.clone(),
                fields: def
                    .fields
                    .iter()
                    .map(|f| convert_field(f, context))
                    .collect(),
                enum_values: vec![],
                union_types: vec![],
                interfaces: def.implements.iter().map(|i| i.node.to_string()).collect(),
                directives,
            },
        )),
        AsyncTypeKind::Enum(def) => Some((
            name.clone(),
            TypeDef {
                kind: TypeKind::Enum,
                name: name.clone(),
                description: description.clone(),
                fields: vec![],
                enum_values: def
                    .values
                    .iter()
                    .map(|v| v.node.value.to_string())
                    .collect(),
                union_types: vec![],
                interfaces: vec![],
                directives,
            },
        )),
        AsyncTypeKind::Union(def) => Some((
            name.clone(),
            TypeDef {
                kind: TypeKind::Union,
                name: name.clone(),
                description: description.clone(),
                fields: vec![],
                enum_values: vec![],
                union_types: def.members.iter().map(|m| m.node.to_string()).collect(),
                interfaces: vec![],
                directives,
            },
        )),
        AsyncTypeKind::InputObject(def) => Some((
            name.clone(),
            TypeDef {
                kind: TypeKind::InputObject,
                name: name.clone(),
                description: description.clone(),
                fields: def
                    .fields
                    .iter()
                    .map(|f| convert_input_field(f, context))
                    .collect(),
                enum_values: vec![],
                union_types: vec![],
                interfaces: vec![],
                directives,
            },
        )),
        AsyncTypeKind::Scalar => Some((
            name.clone(),
            TypeDef {
                kind: TypeKind::Scalar,
                name: name.clone(),
                description: description.clone(),
                fields: vec![],
                enum_values: vec![],
                union_types: vec![],
                interfaces: vec![],
                directives,
            },
        )),
    };
    type_def
}

fn convert_field<'a>(
    field: &Positioned<FieldDefinition>,
    context: &'a ConversionContext,
) -> FieldDef {
    FieldDef {
        name: field.node.name.node.to_string(),
        field_type: convert_gql_type(&field.node.ty.node, context),
        description: get_description(&field.node.description),
        arguments: field
            .node
            .arguments
            .iter()
            .map(|a| ArgumentDef {
                name: a.node.name.node.to_string(),
                arg_type: convert_gql_type(&a.node.ty.node, context),
                description: get_description(&a.node.description),
                default_value: a.node.default_value.as_ref().map(|v| v.node.to_string()),
            })
            .collect(),
        directives: field
            .node
            .directives
            .iter()
            .map(|d| convert_directive(d))
            .collect(),
    }
}

fn convert_input_field<'a>(
    field: &Positioned<InputValueDefinition>,
    context: &'a ConversionContext,
) -> FieldDef {
    FieldDef {
        name: field.node.name.node.to_string(),
        field_type: convert_gql_type(&field.node.ty.node, context),
        description: get_description(&field.node.description),
        arguments: vec![], // Input fields don't have arguments
        directives: field
            .node
            .directives
            .iter()
            .map(|d| convert_directive(d))
            .collect(),
    }
}

fn convert_directive(directive: &Positioned<ConstDirective>) -> DirectiveDef {
    let mut arguments = IndexMap::new();
    for (name, value) in &directive.node.arguments {
        arguments.insert(name.node.to_string(), value.node.to_string());
    }
    DirectiveDef {
        name: directive.node.name.node.to_string(),
        arguments,
    }
}

fn convert_gql_type<'a>(gql_type: &Type, context: &'a ConversionContext) -> GqlType {
    let result = match &gql_type.base {
        BaseType::Named(name) => {
            let type_name = name.to_string();
            let scalar = match type_name.as_str() {
                "String" => GqlScalar::String,
                "Int" => GqlScalar::Int,
                "Float" => GqlScalar::Float,
                "Boolean" => GqlScalar::Boolean,
                "ID" => GqlScalar::Id,
                _ => GqlScalar::Custom(type_name),
            };
            GqlType::Scalar(scalar)
        }
        BaseType::List(inner) => GqlType::List(Box::new(convert_gql_type(inner, context))),
    };
    if gql_type.nullable {
        result
    } else {
        GqlType::NonNull(Box::new(result))
    }
}

// --- IR to JSON Schema Conversion ---

fn convert_type_to_schema(type_def: &TypeDef, context: &ConversionContext) -> JsonValue {
    let mut x_graphql = json!({
        "typeName": type_def.name,
        "kind": format!("{:?}", type_def.kind).to_lowercase(),
    });

    if !type_def.interfaces.is_empty() {
        x_graphql["implements"] = json!(type_def.interfaces);
    }

    if !type_def.directives.is_empty() {
        x_graphql["directives"] = json!(type_def
            .directives
            .iter()
            .map(|d| {
                let mut dir_json = json!({ "name": d.name });
                if !d.arguments.is_empty() {
                    dir_json["arguments"] = json!(d.arguments);
                }
                dir_json
            })
            .collect::<Vec<_>>());

        // Extract federation directives
        let mut federation = json!({});
        let mut has_federation = false;

        for dir in &type_def.directives {
            match dir.name.as_str() {
                "key" => {
                    if let Some(fields) = dir.arguments.get("fields") {
                        let fields_str = fields.trim_matches('"');
                        let resolvable = dir
                            .arguments
                            .get("resolvable")
                            .map(|v| v != "false")
                            .unwrap_or(true);

                        let key_obj = if resolvable {
                            json!({ "fields": fields_str, "resolvable": true })
                        } else {
                            json!({ "fields": fields_str, "resolvable": false })
                        };

                        if let Some(keys) =
                            federation.get_mut("keys").and_then(|v| v.as_array_mut())
                        {
                            keys.push(key_obj);
                        } else {
                            federation["keys"] = json!([key_obj]);
                        }
                        has_federation = true;
                    }
                }
                "shareable" => {
                    federation["shareable"] = json!(true);
                    has_federation = true;
                }
                "extends" => {
                    federation["extends"] = json!(true);
                    has_federation = true;
                }
                "interfaceObject" => {
                    federation["interfaceObject"] = json!(true);
                    has_federation = true;
                }
                "authenticated" => {
                    federation["authenticated"] = json!(true);
                    has_federation = true;
                }
                "requiresScopes" => {
                    if let Some(scopes) = dir.arguments.get("scopes") {
                        // scopes is usually a list of lists of strings, simplified here
                        federation["requiresScopes"] = json!(scopes);
                        has_federation = true;
                    }
                }
                _ => {}
            }
        }

        if has_federation {
            x_graphql["federation"] = federation;
        }
    }

    let mut schema = json!({
        "x-graphql": x_graphql
    });

    if let Some(description) = &type_def.description {
        schema["description"] = json!(description);
    }

    match type_def.kind {
        TypeKind::Object | TypeKind::Interface | TypeKind::InputObject => {
            schema["type"] = json!("object");
            let mut properties = IndexMap::new();
            let mut required = Vec::new();

            for field in &type_def.fields {
                let (prop_schema, is_req) = gql_type_to_json_schema(&field.field_type, context);
                let mut final_prop_schema = prop_schema;

                let mut field_x_graphql = json!({});
                if field.name != camel_to_snake(&field.name) {
                    field_x_graphql["fieldName"] = json!(field.name);
                }

                // Add arguments
                if !field.arguments.is_empty() {
                    let args: IndexMap<String, JsonValue> = field
                        .arguments
                        .iter()
                        .map(|a| {
                            let mut arg_schema = json!({
                                "type": gql_type_to_string(&a.arg_type)
                            });
                            if let Some(desc) = &a.description {
                                arg_schema["description"] = json!(desc);
                            }
                            if let Some(default) = &a.default_value {
                                arg_schema["default"] = json!(default);
                            }
                            (a.name.clone(), arg_schema)
                        })
                        .collect();
                    field_x_graphql["args"] = json!(args);
                }

                // Add directives
                if !field.directives.is_empty() {
                    field_x_graphql["directives"] = json!(field
                        .directives
                        .iter()
                        .map(|d| {
                            let mut dir_json = json!({ "name": d.name });
                            if !d.arguments.is_empty() {
                                dir_json["arguments"] = json!(d.arguments);
                            }
                            dir_json
                        })
                        .collect::<Vec<_>>());

                    // Handle federation field directives
                    let mut federation = json!({});
                    let mut has_federation = false;

                    for dir in &field.directives {
                        match dir.name.as_str() {
                            "external" => {
                                federation["external"] = json!(true);
                                has_federation = true;
                            }
                            "requires" => {
                                if let Some(fields) = dir.arguments.get("fields") {
                                    federation["requires"] = json!(fields.trim_matches('"'));
                                    has_federation = true;
                                }
                            }
                            "provides" => {
                                if let Some(fields) = dir.arguments.get("fields") {
                                    federation["provides"] = json!(fields.trim_matches('"'));
                                    has_federation = true;
                                }
                            }
                            "override" => {
                                if let Some(from) = dir.arguments.get("from") {
                                    federation["override"] =
                                        json!({ "from": from.trim_matches('"') });
                                    has_federation = true;
                                }
                            }
                            "shareable" => {
                                federation["shareable"] = json!(true);
                                has_federation = true;
                            }
                            _ => {}
                        }
                    }
                    if has_federation {
                        field_x_graphql["federation"] = federation;
                    }
                }

                if field_x_graphql
                    .as_object()
                    .map(|o| !o.is_empty())
                    .unwrap_or(false)
                {
                    final_prop_schema["x-graphql"] = field_x_graphql;
                }

                if let Some(desc) = &field.description {
                    final_prop_schema["description"] = json!(desc);
                }

                let prop_name = camel_to_snake(&field.name);
                if is_req {
                    required.push(prop_name.clone());
                }
                properties.insert(prop_name, final_prop_schema);
            }
            schema["properties"] = json!(properties);
            if !required.is_empty() {
                schema["required"] = json!(required);
            }
        }
        TypeKind::Enum => {
            schema["type"] = json!("string");
            schema["enum"] = json!(type_def.enum_values);
        }
        TypeKind::Union => {
            schema["oneOf"] = json!(type_def
                .union_types
                .iter()
                .map(|t| json!({ "$ref": format!("#/definitions/{}", t) }))
                .collect::<Vec<_>>());

            // Union specific x-graphql info
            if let Some(x) = schema.get_mut("x-graphql").and_then(|v| v.as_object_mut()) {
                x.insert("unionTypes".to_string(), json!(type_def.union_types));
            }
        }
        TypeKind::Scalar => {
            schema["type"] = json!("string"); // Default, can be overridden by user
        }
    }
    schema
}

fn gql_type_to_string(gql_type: &GqlType) -> String {
    match gql_type {
        GqlType::Scalar(scalar) => match scalar {
            GqlScalar::String => "String".to_string(),
            GqlScalar::Int => "Int".to_string(),
            GqlScalar::Float => "Float".to_string(),
            GqlScalar::Boolean => "Boolean".to_string(),
            GqlScalar::Id => "ID".to_string(),
            GqlScalar::Custom(name) => name.clone(),
        },
        GqlType::List(inner) => format!("[{}]", gql_type_to_string(inner)),
        GqlType::NonNull(inner) => format!("{}!", gql_type_to_string(inner)),
    }
}

fn gql_type_to_json_schema(gql_type: &GqlType, context: &ConversionContext) -> (JsonValue, bool) {
    match gql_type {
        GqlType::Scalar(scalar) => (
            match scalar {
                GqlScalar::String => json!({"type": "string"}),
                GqlScalar::Int => json!({"type": "integer"}),
                GqlScalar::Float => json!({"type": "number"}),
                GqlScalar::Boolean => json!({"type": "boolean"}),
                GqlScalar::Id => json!({"type": "string", "format": "uuid"}),
                GqlScalar::Custom(name) => json!({ "$ref": format!("#/definitions/{}", name) }),
            },
            false,
        ),
        GqlType::List(inner) => (
            json!({
                "type": "array",
                "items": gql_type_to_json_schema(inner, context).0,
            }),
            false,
        ),
        GqlType::NonNull(inner) => {
            let (schema, _) = gql_type_to_json_schema(inner, context);
            (schema, true)
        }
    }
}

// --- Utility Functions ---

fn camel_to_snake(s: &str) -> String {
    let mut snake = String::new();
    for (i, ch) in s.chars().enumerate() {
        if i > 0 && ch.is_uppercase() {
            snake.push('_');
        }
        snake.push(ch.to_ascii_lowercase());
    }
    snake
}

