//! Core types for JSON Schema x GraphQL conversion

use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Direction of conversion
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum ConversionDirection {
    /// Convert from JSON Schema to GraphQL SDL
    JsonSchemaToGraphQL,
    /// Convert from GraphQL SDL to JSON Schema
    GraphQLToJsonSchema,
}

/// Options for conversion
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ConversionOptions {
    /// Whether to validate input before conversion
    pub validate: bool,
    /// Whether to include description fields
    pub include_descriptions: bool,
    /// Whether to preserve field order from source
    pub preserve_field_order: bool,
    /// Apollo Federation version (1 or 2)
    pub federation_version: u8,
    /// Whether to automatically infer ID scalar for fields named "id", "_id", etc.
    pub infer_ids: bool,
}

impl Default for ConversionOptions {
    fn default() -> Self {
        Self {
            validate: true,
            include_descriptions: true,
            preserve_field_order: true,
            federation_version: 2,
            infer_ids: false,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum GqlScalar {
    String,
    Int,
    Float,
    Boolean,
    Id,
    Custom(String),
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum GqlType {
    Scalar(GqlScalar),
    List(Box<GqlType>),
    NonNull(Box<GqlType>),
}

#[derive(Debug, Clone, PartialEq)]
pub enum GqlValue {
    Variable(String),
    Int(i64),
    Float(f64),
    String(String),
    Boolean(bool),
    Null,
    Enum(String),
    List(Vec<GqlValue>),
    Object(HashMap<String, GqlValue>),
}

/// GraphQL type information
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct GraphQLType {
    /// Type name (e.g., "String", "User")
    pub name: String,
    /// Whether the type is required (non-null)
    pub required: bool,
    /// Whether the type is a list
    pub is_list: bool,
    /// Whether the list items are required (for lists only)
    pub list_item_required: bool,
}

impl GraphQLType {
    /// Create a new GraphQL type
    pub fn new(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            required: false,
            is_list: false,
            list_item_required: false,
        }
    }

    /// Make this type required (non-null)
    pub fn required(mut self) -> Self {
        self.required = true;
        self
    }

    /// Make this type a list
    pub fn list(mut self) -> Self {
        self.is_list = true;
        self
    }

    /// Make list items required
    pub fn list_item_required(mut self) -> Self {
        self.list_item_required = true;
        self
    }

    /// Convert to GraphQL SDL notation
    pub fn to_sdl(&self) -> String {
        let mut result = String::new();

        if self.is_list {
            result.push('[');
            result.push_str(&self.name);
            if self.list_item_required {
                result.push('!');
            }
            result.push(']');
        } else {
            result.push_str(&self.name);
        }

        if self.required {
            result.push('!');
        }

        result
    }

    /// Parse from GraphQL SDL notation
    pub fn from_sdl(sdl: &str) -> Result<Self, String> {
        let mut chars = sdl.trim().chars().peekable();
        let mut is_list = false;
        let mut list_item_required = false;
        let mut name = String::new();
        let mut required = false;

        // Check for list
        if chars.peek() == Some(&'[') {
            is_list = true;
            chars.next(); // consume '['

            // Read type name
            while let Some(&ch) = chars.peek() {
                if ch == '!' {
                    list_item_required = true;
                    chars.next();
                } else if ch == ']' {
                    chars.next();
                    break;
                } else {
                    name.push(ch);
                    chars.next();
                }
            }
        } else {
            // Not a list, read type name
            while let Some(&ch) = chars.peek() {
                if ch == '!' {
                    break;
                } else {
                    name.push(ch);
                    chars.next();
                }
            }
        }

        // Check for required
        if chars.peek() == Some(&'!') {
            required = true;
        }

        if name.is_empty() {
            return Err("Empty type name".to_string());
        }

        Ok(Self {
            name: name.trim().to_string(),
            required,
            is_list,
            list_item_required,
        })
    }
}

/// GraphQL field argument
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GraphQLArgument {
    /// Argument name
    pub name: String,
    /// Argument type
    pub type_info: GraphQLType,
    /// Optional description
    pub description: Option<String>,
    /// Optional default value
    pub default_value: Option<String>,
}

/// GraphQL field definition
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GraphQLField {
    /// Field name
    pub name: String,
    /// Field type
    pub type_info: GraphQLType,
    /// Optional description
    pub description: Option<String>,
    /// Field arguments
    pub arguments: Vec<GraphQLArgument>,
    /// Directives applied to this field
    pub directives: Vec<GraphQLDirective>,
}

/// GraphQL directive
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GraphQLDirective {
    /// Directive name (without @)
    pub name: String,
    /// Directive arguments
    pub arguments: HashMap<String, String>,
}

impl GraphQLDirective {
    /// Create a new directive
    pub fn new(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            arguments: HashMap::new(),
        }
    }

    /// Add an argument to the directive
    pub fn with_arg(mut self, key: impl Into<String>, value: impl Into<String>) -> Self {
        self.arguments.insert(key.into(), value.into());
        self
    }

    /// Convert to SDL notation
    pub fn to_sdl(&self) -> String {
        let mut result = format!("@{}", self.name);

        if !self.arguments.is_empty() {
            result.push('(');
            let args: Vec<String> = self
                .arguments
                .iter()
                .map(|(k, v)| format!("{}: {}", k, v))
                .collect();
            result.push_str(&args.join(", "));
            result.push(')');
        }

        result
    }
}

/// GraphQL type definition (Object, Interface, etc.)
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GraphQLTypeDefinition {
    /// Type kind
    pub kind: GraphQLTypeKind,
    /// Type name
    pub name: String,
    /// Optional description
    pub description: Option<String>,
    /// Fields (for objects and interfaces)
    pub fields: Vec<GraphQLField>,
    /// Interfaces this type implements
    pub implements: Vec<String>,
    /// Directives applied to this type
    pub directives: Vec<GraphQLDirective>,
    /// Enum values (for enums only)
    pub enum_values: Vec<GraphQLEnumValue>,
    /// Union member types (for unions only)
    pub union_types: Vec<String>,
}

/// GraphQL type kind
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum GraphQLTypeKind {
    Object,
    Interface,
    Enum,
    Union,
    InputObject,
    Scalar,
}

/// GraphQL enum value
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GraphQLEnumValue {
    /// Value name
    pub name: String,
    /// Optional description
    pub description: Option<String>,
    /// Directives applied to this enum value
    pub directives: Vec<GraphQLDirective>,
}

/// JSON Schema property definition
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct JsonSchemaProperty {
    /// Property name (snake_case)
    pub name: String,
    /// JSON Schema type
    pub schema_type: JsonSchemaType,
    /// Optional description
    pub description: Option<String>,
    /// GraphQL field name (camelCase)
    pub graphql_name: Option<String>,
    /// GraphQL type override
    pub graphql_type: Option<String>,
    /// Whether this property is required
    pub required: bool,
}

/// JSON Schema type
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum JsonSchemaType {
    String,
    Number,
    Integer,
    Boolean,
    Object,
    Array,
    Null,
}

impl JsonSchemaType {
    /// Convert from JSON Schema type string
    pub fn from_str(s: &str) -> Option<Self> {
        match s {
            "string" => Some(Self::String),
            "number" => Some(Self::Number),
            "integer" => Some(Self::Integer),
            "boolean" => Some(Self::Boolean),
            "object" => Some(Self::Object),
            "array" => Some(Self::Array),
            "null" => Some(Self::Null),
            _ => None,
        }
    }

    /// Convert to JSON Schema type string
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::String => "string",
            Self::Number => "number",
            Self::Integer => "integer",
            Self::Boolean => "boolean",
            Self::Object => "object",
            Self::Array => "array",
            Self::Null => "null",
        }
    }

    /// Get corresponding GraphQL scalar type
    pub fn to_graphql_scalar(&self) -> Option<&'static str> {
        match self {
            Self::String => Some("String"),
            Self::Number => Some("Float"),
            Self::Integer => Some("Int"),
            Self::Boolean => Some("Boolean"),
            Self::Object => None, // Objects are custom types
            Self::Array => None,  // Arrays are lists
            Self::Null => None,   // Null is not directly representable
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_graphql_type_to_sdl() {
        let type_info = GraphQLType::new("String").required();
        assert_eq!(type_info.to_sdl(), "String!");

        let list_type = GraphQLType::new("String").list().required();
        assert_eq!(list_type.to_sdl(), "[String]!");

        let required_list = GraphQLType::new("String")
            .list()
            .list_item_required()
            .required();
        assert_eq!(required_list.to_sdl(), "[String!]!");
    }

    #[test]
    fn test_graphql_type_from_sdl() {
        let result = GraphQLType::from_sdl("String!").unwrap();
        assert_eq!(result.name, "String");
        assert!(result.required);
        assert!(!result.is_list);

        let list_result = GraphQLType::from_sdl("[String]!").unwrap();
        assert_eq!(list_result.name, "String");
        assert!(list_result.required);
        assert!(list_result.is_list);
        assert!(!list_result.list_item_required);

        let required_list = GraphQLType::from_sdl("[String!]!").unwrap();
        assert_eq!(required_list.name, "String");
        assert!(required_list.required);
        assert!(required_list.is_list);
        assert!(required_list.list_item_required);
    }

    #[test]
    fn test_directive_to_sdl() {
        let directive = GraphQLDirective::new("key").with_arg("fields", "\"id\"");
        assert_eq!(directive.to_sdl(), "@key(fields: \"id\")");

        let simple = GraphQLDirective::new("deprecated");
        assert_eq!(simple.to_sdl(), "@deprecated");
    }

    #[test]
    fn test_json_schema_type_conversion() {
        assert_eq!(
            JsonSchemaType::from_str("string"),
            Some(JsonSchemaType::String)
        );
        assert_eq!(JsonSchemaType::String.as_str(), "string");
        assert_eq!(JsonSchemaType::String.to_graphql_scalar(), Some("String"));
        assert_eq!(JsonSchemaType::Number.to_graphql_scalar(), Some("Float"));
        assert_eq!(JsonSchemaType::Integer.to_graphql_scalar(), Some("Int"));
    }
}

//! Validation utilities for JSON Schema and GraphQL SDL

use crate::error::{ConversionError, Result};
use regex::Regex;
use serde_json::Value as JsonValue;
use std::sync::OnceLock;

/// Regex for valid GraphQL names: /^[_A-Za-z][_0-9A-Za-z]*$/
fn graphql_name_regex() -> &'static Regex {
    static REGEX: OnceLock<Regex> = OnceLock::new();
    REGEX.get_or_init(|| Regex::new(r"^[_A-Za-z][_0-9A-Za-z]*$").unwrap())
}

/// Regex for valid GraphQL type references (including lists and non-null)
fn graphql_type_regex() -> &'static Regex {
    static REGEX: OnceLock<Regex> = OnceLock::new();
    REGEX.get_or_init(|| Regex::new(r"^(\[)?[_A-Za-z][_0-9A-Za-z]*!?(\])?!?$").unwrap())
}

/// Regex for valid URLs
fn url_regex() -> &'static Regex {
    static REGEX: OnceLock<Regex> = OnceLock::new();
    REGEX.get_or_init(|| Regex::new(r"^https?://[^\s/$.?#].[^\s]*$").unwrap())
}

/// Validate a GraphQL name
pub fn validate_graphql_name(name: &str) -> Result<()> {
    if name.is_empty() {
        return Err(ConversionError::invalid_name(name, "name cannot be empty"));
    }

    if !graphql_name_regex().is_match(name) {
        return Err(ConversionError::invalid_name(
            name,
            "name must match /^[_A-Za-z][_0-9A-Za-z]*$/",
        ));
    }

    // Check for GraphQL reserved names
    if is_reserved_name(name) {
        return Err(ConversionError::invalid_name(
            name,
            "name is reserved by GraphQL specification",
        ));
    }

    Ok(())
}

/// Check if a name is reserved by GraphQL
fn is_reserved_name(name: &str) -> bool {
    // Names starting with __ are reserved
    name.starts_with("__")
}

/// Validate a GraphQL type reference
pub fn validate_graphql_type(type_str: &str) -> Result<()> {
    if type_str.is_empty() {
        return Err(ConversionError::InvalidType(
            "type cannot be empty".to_string(),
        ));
    }

    if !graphql_type_regex().is_match(type_str) {
        return Err(ConversionError::InvalidType(format!(
            "invalid GraphQL type format: {}",
            type_str
        )));
    }

    Ok(())
}

/// Validate federation field selection syntax
pub fn validate_federation_fields(fields: &str) -> Result<()> {
    if fields.is_empty() {
        return Err(ConversionError::FederationError(
            "fields selection cannot be empty".to_string(),
        ));
    }

    // Basic validation - more complex parsing would be needed for full support
    if !fields.chars().all(|c| {
        c.is_alphanumeric() || c == '_' || c == ' ' || c == '"' || c == ',' || c == '{' || c == '}'
    }) {
        return Err(ConversionError::FederationError(format!(
            "invalid characters in fields selection: {}",
            fields
        )));
    }

    Ok(())
}

/// Validate a URL
pub fn validate_url(url: &str) -> Result<()> {
    if !url_regex().is_match(url) {
        return Err(ConversionError::ValidationError(format!(
            "invalid URL format: {}",
            url
        )));
    }
    Ok(())
}

/// Validate JSON Schema structure
pub fn validate_json_schema(schema: &JsonValue) -> Result<()> {
    let mut errors = Vec::new();

    // Check if it's an object
    if !schema.is_object() {
        return Err(ConversionError::InvalidJsonSchema(
            "schema must be an object".to_string(),
        ));
    }

    let obj = schema.as_object().unwrap();

    // Validate $schema if present
    if let Some(schema_version) = obj.get("$schema") {
        if let Some(version_str) = schema_version.as_str() {
            if !version_str.contains("json-schema.org") {
                errors.push(ConversionError::validation(format!(
                    "invalid $schema URL: {}",
                    version_str
                )));
            }
        }
    }

    // Validate x-graphql-type-name if present
    if let Some(type_name) = obj.get("x-graphql-type-name") {
        if let Some(name) = type_name.as_str() {
            if let Err(e) = validate_graphql_name(name) {
                errors.push(e);
            }
        } else {
            errors.push(ConversionError::invalid_extension(
                "x-graphql-type-name must be a string",
            ));
        }
    }

    // Validate x-graphql-type if present
    if let Some(gql_type) = obj.get("x-graphql-type") {
        if let Some(type_str) = gql_type.as_str() {
            if let Err(e) = validate_graphql_type(type_str) {
                errors.push(e);
            }
        } else {
            errors.push(ConversionError::invalid_extension(
                "x-graphql-type must be a string",
            ));
        }
    }

    // Validate properties recursively
    if let Some(properties) = obj.get("properties") {
        if let Some(props_obj) = properties.as_object() {
            for (prop_name, prop_schema) in props_obj {
                // Validate property name format
                if prop_name.is_empty() {
                    errors.push(ConversionError::validation(
                        "property name cannot be empty".to_string(),
                    ));
                }

                // Recursively validate nested schemas
                if let Err(e) = validate_json_schema(prop_schema) {
                    errors.push(e);
                }
            }
        }
    }

    // Validate items for arrays
    if let Some(items) = obj.get("items") {
        if let Err(e) = validate_json_schema(items) {
            errors.push(e);
        }
    }

    // Validate x-graphql-directives if present
    if let Some(directives) = obj.get("x-graphql-directives") {
        if let Some(dir_array) = directives.as_array() {
            for directive in dir_array {
                if let Err(e) = validate_directive(directive) {
                    errors.push(e);
                }
            }
        } else {
            errors.push(ConversionError::invalid_extension(
                "x-graphql-directives must be an array",
            ));
        }
    }

    if errors.is_empty() {
        Ok(())
    } else {
        Err(ConversionError::combine(errors))
    }
}

/// Validate a directive definition
fn validate_directive(directive: &JsonValue) -> Result<()> {
    let obj = directive.as_object().ok_or_else(|| {
        ConversionError::InvalidDirective("directive must be an object".to_string())
    })?;

    // Validate directive name
    if let Some(name) = obj.get("name") {
        if let Some(name_str) = name.as_str() {
            validate_graphql_name(name_str)?;
        } else {
            return Err(ConversionError::InvalidDirective(
                "directive name must be a string".to_string(),
            ));
        }
    } else {
        return Err(ConversionError::InvalidDirective(
            "directive must have a name".to_string(),
        ));
    }

    // Validate arguments if present
    if let Some(args) = obj.get("arguments") {
        if !args.is_object() {
            return Err(ConversionError::InvalidDirective(
                "directive arguments must be an object".to_string(),
            ));
        }
    }

    Ok(())
}

/// Validate GraphQL SDL syntax (basic validation)
pub fn validate_graphql_sdl(sdl: &str) -> Result<()> {
    if sdl.trim().is_empty() {
        return Err(ConversionError::InvalidGraphQLSdl(
            "SDL cannot be empty".to_string(),
        ));
    }

    // Basic syntax checks
    let lines: Vec<&str> = sdl.lines().collect();
    let mut errors = Vec::new();
    let mut brace_count = 0;
    let mut in_type_definition = false;
    let mut is_enum_definition = false;
    let mut in_block_string = false;

    for (line_num, line) in lines.iter().enumerate() {
        let trimmed = line.trim();

        // Handle block strings
        if trimmed.contains("\"\"\"") {
            let count = trimmed.matches("\"\"\"").count();
            if count % 2 != 0 {
                in_block_string = !in_block_string;
            }
            continue;
        }

        if in_block_string {
            continue;
        }

        // Skip empty lines and comments
        if trimmed.is_empty() || trimmed.starts_with('#') {
            continue;
        }

        // Count braces for matching
        brace_count += trimmed.matches('{').count() as i32;
        brace_count -= trimmed.matches('}').count() as i32;

        // Check for type definition keywords
        if trimmed.starts_with("type ")
            || trimmed.starts_with("interface ")
            || trimmed.starts_with("enum ")
            || trimmed.starts_with("union ")
            || trimmed.starts_with("input ")
            || trimmed.starts_with("scalar ")
        {
            in_type_definition = true;
            is_enum_definition = trimmed.starts_with("enum ");

            // Extract type name after keyword
            let parts: Vec<&str> = trimmed.split_whitespace().collect();
            if parts.len() >= 2 {
                let type_name = parts[1].trim_end_matches('{').trim();
                if let Err(e) = validate_graphql_name(type_name) {
                    errors.push(ConversionError::InvalidGraphQLSdl(format!(
                        "Line {}: {}",
                        line_num + 1,
                        e
                    )));
                }
            }
        }

        // Check for field syntax inside type definitions
        if in_type_definition && !is_enum_definition && brace_count > 0 && trimmed.contains(':') {
            // Basic field validation: should have "name: Type" format
            if !trimmed.starts_with("type ")
                && !trimmed.starts_with("interface ")
                && !trimmed.starts_with("enum ")
                && !trimmed.starts_with("union ")
                && !trimmed.starts_with("input ")
                && !trimmed.starts_with("scalar ")
            {
                let parts: Vec<&str> = trimmed.split(':').collect();
                if parts.len() < 2 {
                    errors.push(ConversionError::InvalidGraphQLSdl(format!(
                        "Line {}: Invalid field syntax",
                        line_num + 1
                    )));
                }
            }
        }

        // Check for text without colons inside type bodies (likely invalid)
        if in_type_definition
            && !is_enum_definition
            && brace_count > 0
            && !trimmed.is_empty()
            && !trimmed.contains(':')
            && !trimmed.starts_with('@')
            && !trimmed.contains('{')
            && !trimmed.contains('}')
            && !trimmed.starts_with("\"")
            && !trimmed.starts_with("type ")
            && !trimmed.starts_with("interface ")
            && !trimmed.starts_with("enum ")
            && !trimmed.starts_with("union ")
            && !trimmed.starts_with("input ")
            && !trimmed.starts_with("scalar ")
        {
            // Check if it looks like it should be a field (has alphanumeric chars)
            if trimmed.chars().any(|c| c.is_alphanumeric()) {
                let msg = if trimmed.contains('(') && trimmed.contains(')') {
                    "Invalid field/argument definition - check syntax"
                } else {
                    "Invalid field definition - missing colon between name and type"
                };

                errors.push(ConversionError::InvalidGraphQLSdl(format!(
                    "Line {}: {}",
                    line_num + 1,
                    msg
                )));
            }
        }

        if brace_count == 0 && in_type_definition {
            in_type_definition = false;
            is_enum_definition = false;
        }
    }

    // Check for unmatched braces
    if brace_count != 0 {
        errors.push(ConversionError::InvalidGraphQLSdl(
            "Unmatched braces in SDL".to_string(),
        ));
    }

    if errors.is_empty() {
        Ok(())
    } else {
        Err(ConversionError::combine(errors))
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::json;

    #[test]
    fn test_validate_graphql_name() {
        assert!(validate_graphql_name("User").is_ok());
        assert!(validate_graphql_name("_privateField").is_ok());
        assert!(validate_graphql_name("field123").is_ok());

        assert!(validate_graphql_name("").is_err());
        assert!(validate_graphql_name("123invalid").is_err());
        assert!(validate_graphql_name("invalid-name").is_err());
        assert!(validate_graphql_name("__reserved").is_err());
    }

    #[test]
    fn test_validate_graphql_type() {
        assert!(validate_graphql_type("String").is_ok());
        assert!(validate_graphql_type("String!").is_ok());
        assert!(validate_graphql_type("[String]").is_ok());
        assert!(validate_graphql_type("[String!]!").is_ok());

        assert!(validate_graphql_type("").is_err());
        assert!(validate_graphql_type("123Invalid").is_err());
    }

    #[test]
    fn test_validate_url() {
        assert!(validate_url("https://example.com").is_ok());
        assert!(validate_url("http://localhost:8080/path").is_ok());

        assert!(validate_url("not-a-url").is_err());
        assert!(validate_url("ftp://example.com").is_err());
    }

    #[test]
    fn test_validate_json_schema() {
        let valid_schema = json!({
            "$schema": "https://json-schema.org/draft/2020-12/schema",
            "type": "object",
            "x-graphql-type-name": "User",
            "properties": {
                "id": {
                    "type": "string",
                    "x-graphql-type": "ID!"
                }
            }
        });

        assert!(validate_json_schema(&valid_schema).is_ok());

        let invalid_schema = json!({
            "type": "object",
            "x-graphql-type-name": "123Invalid"
        });

        assert!(validate_json_schema(&invalid_schema).is_err());
    }

    #[test]
    fn test_validate_directive() {
        let valid_directive = json!({
            "name": "key",
            "arguments": {
                "fields": "id"
            }
        });

        assert!(validate_directive(&valid_directive).is_ok());

        let invalid_directive = json!({
            "arguments": {}
        });

        assert!(validate_directive(&invalid_directive).is_err());
    }

    #[test]
    fn test_validate_graphql_sdl() {
        let valid_sdl = r#"
            type User {
                id: ID!
                name: String
            }
        "#;

        assert!(validate_graphql_sdl(valid_sdl).is_ok());

        let invalid_sdl = "";
        assert!(validate_graphql_sdl(invalid_sdl).is_err());
    }

    #[test]
    fn test_reserved_names() {
        assert!(is_reserved_name("__typename"));
        assert!(is_reserved_name("__schema"));
        assert!(!is_reserved_name("_privateField"));
        assert!(!is_reserved_name("User"));
    }
}

//! WASM bindings for JSON Schema x GraphQL converter

use crate::{ConversionDirection, ConversionOptions, Converter};
use serde::{Deserialize, Serialize};
use wasm_bindgen::prelude::*;

/// Initialize panic hook for better error messages in browser
#[wasm_bindgen(start)]
pub fn init() {
    console_error_panic_hook::set_once();
}

/// WASM-compatible conversion options
#[wasm_bindgen]
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WasmConversionOptions {
    validate: bool,
    include_descriptions: bool,
    preserve_field_order: bool,
    federation_version: u8,
    infer_ids: bool,
}

#[wasm_bindgen]
impl WasmConversionOptions {
    #[wasm_bindgen(constructor)]
    pub fn new() -> Self {
        Self {
            validate: true,
            include_descriptions: true,
            preserve_field_order: true,
            federation_version: 2,
            infer_ids: false,
        }
    }

    #[wasm_bindgen(getter)]
    pub fn validate(&self) -> bool {
        self.validate
    }

    #[wasm_bindgen(setter)]
    pub fn set_validate(&mut self, value: bool) {
        self.validate = value;
    }

    #[wasm_bindgen(getter)]
    pub fn include_descriptions(&self) -> bool {
        self.include_descriptions
    }

    #[wasm_bindgen(setter)]
    pub fn set_include_descriptions(&mut self, value: bool) {
        self.include_descriptions = value;
    }

    #[wasm_bindgen(getter)]
    pub fn preserve_field_order(&self) -> bool {
        self.preserve_field_order
    }

    #[wasm_bindgen(setter)]
    pub fn set_preserve_field_order(&mut self, value: bool) {
        self.preserve_field_order = value;
    }

    #[wasm_bindgen(getter)]
    pub fn federation_version(&self) -> u8 {
        self.federation_version
    }

    #[wasm_bindgen(setter)]
    pub fn set_federation_version(&mut self, value: u8) {
        self.federation_version = value;
    }

    #[wasm_bindgen(getter)]
    pub fn infer_ids(&self) -> bool {
        self.infer_ids
    }

    #[wasm_bindgen(setter)]
    pub fn set_infer_ids(&mut self, value: bool) {
        self.infer_ids = value;
    }

    /// Convert to internal options type
    fn to_internal(&self) -> ConversionOptions {
        ConversionOptions {
            validate: self.validate,
            include_descriptions: self.include_descriptions,
            preserve_field_order: self.preserve_field_order,
            federation_version: self.federation_version,
            infer_ids: self.infer_ids,
        }
    }
}

impl Default for WasmConversionOptions {
    fn default() -> Self {
        Self::new()
    }
}

/// WASM-compatible converter
#[wasm_bindgen]
pub struct WasmConverter {
    converter: Converter,
}

#[wasm_bindgen]
impl WasmConverter {
    /// Create a new converter with default options
    #[wasm_bindgen(constructor)]
    pub fn new() -> Self {
        Self {
            converter: Converter::new(),
        }
    }

    /// Create a new converter with custom options
    #[wasm_bindgen(js_name = withOptions)]
    pub fn with_options(options: &WasmConversionOptions) -> Self {
        Self {
            converter: Converter::with_options(options.to_internal()),
        }
    }

    /// Convert JSON Schema to GraphQL SDL
    #[wasm_bindgen(js_name = jsonSchemaToGraphQL)]
    pub fn json_schema_to_graphql(&self, json_schema: &str) -> Result<String, JsValue> {
        self.converter
            .json_schema_to_graphql(json_schema)
            .map_err(Into::into)
    }

    /// Convert GraphQL SDL to JSON Schema
    #[wasm_bindgen(js_name = graphqlToJsonSchema)]
    pub fn graphql_to_json_schema(&self, graphql_sdl: &str) -> Result<String, JsValue> {
        self.converter
            .graphql_to_json_schema(graphql_sdl)
            .map_err(Into::into)
    }

    /// Convert between formats (bidirectional)
    pub fn convert(&self, input: &str, direction: &str) -> Result<String, JsValue> {
        let dir = match direction {
            "json-to-graphql" | "jsonToGraphQL" => ConversionDirection::JsonSchemaToGraphQL,
            "graphql-to-json" | "graphqlToJson" => ConversionDirection::GraphQLToJsonSchema,
            _ => {
                return Err(JsValue::from_str(&format!(
                    "Invalid direction: {}. Use 'json-to-graphql' or 'graphql-to-json'",
                    direction
                )))
            }
        };

        self.converter.convert(input, dir).map_err(Into::into)
    }

    /// Clear the conversion cache (if caching is enabled)
    #[cfg(feature = "caching")]
    #[wasm_bindgen(js_name = clearCache)]
    pub fn clear_cache(&self) {
        self.converter.clear_cache();
    }
}

impl Default for WasmConverter {
    fn default() -> Self {
        Self::new()
    }
}

/// Standalone function to convert JSON Schema to GraphQL SDL
#[wasm_bindgen(js_name = jsonSchemaToGraphQL)]
pub fn json_schema_to_graphql(json_schema: &str) -> Result<String, JsValue> {
    let converter = Converter::new();
    converter
        .json_schema_to_graphql(json_schema)
        .map_err(Into::into)
}

/// Standalone function to convert GraphQL SDL to JSON Schema
#[wasm_bindgen(js_name = graphqlToJsonSchema)]
pub fn graphql_to_json_schema(graphql_sdl: &str) -> Result<String, JsValue> {
    let converter = Converter::new();
    converter
        .graphql_to_json_schema(graphql_sdl)
        .map_err(Into::into)
}

/// Validate JSON Schema
#[wasm_bindgen(js_name = validateJsonSchema)]
pub fn validate_json_schema(json_schema: &str) -> Result<bool, JsValue> {
    use crate::error::ConversionError;
    use crate::validator;

    let schema: serde_json::Value =
        serde_json::from_str(json_schema).map_err(ConversionError::from)?;

    validator::validate_json_schema(&schema)
        .map(|_| true)
        .map_err(Into::into)
}

/// Validate GraphQL SDL
#[wasm_bindgen(js_name = validateGraphQLSdl)]
pub fn validate_graphql_sdl(graphql_sdl: &str) -> Result<bool, JsValue> {
    use crate::validator;

    validator::validate_graphql_sdl(graphql_sdl)
        .map(|_| true)
        .map_err(Into::into)
}

/// Validate a GraphQL name
#[wasm_bindgen(js_name = validateGraphQLName)]
pub fn validate_graphql_name(name: &str) -> Result<bool, JsValue> {
    use crate::validator;

    validator::validate_graphql_name(name)
        .map(|_| true)
        .map_err(Into::into)
}

/// Get library version
#[wasm_bindgen(js_name = getVersion)]
pub fn get_version() -> String {
    env!("CARGO_PKG_VERSION").to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_wasm_options() {
        let mut options = WasmConversionOptions::new();
        assert_eq!(options.validate(), true);

        options.set_validate(false);
        assert_eq!(options.validate(), false);

        options.set_federation_version(1);
        assert_eq!(options.federation_version(), 1);
    }

    #[test]
    fn test_wasm_converter() {
        let converter = WasmConverter::new();
        let json_schema = r#"{
            "type": "object",
            "x-graphql-type-name": "User",
            "properties": {
                "id": {
                    "type": "string",
                    "x-graphql-type": "ID!"
                }
            }
        }"#;

        let result = converter.json_schema_to_graphql(json_schema);
        assert!(result.is_ok());
    }

    #[test]
    #[cfg(target_arch = "wasm32")]
    fn test_direction_parsing() {
        let converter = WasmConverter::new();
        let input = r#"{"type": "object", "x-graphql-type-name": "Test"}"#;

        assert!(converter.convert(input, "json-to-graphql").is_ok());
        assert!(converter.convert(input, "jsonToGraphQL").is_ok());
        assert!(converter.convert(input, "invalid").is_err());
    }
}
